                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }
    for (; i_out_y < out_tensor_dim; i_out_y++)
