    NDS_VEC_VLB_V(NDS_VEC_V4, pB);
    NDS_VEC_VLB_V(NDS_VEC_V5, pB2);
    NDS_VEC_VLB_V(NDS_VEC_V6, pB3);
    NDS_VEC_VLB_V(NDS_VEC_V7, pB4);

    //bump pointers and update loop counter
    colCnt -= vl;
    pA += vl;
    pA2 += vl;
    pA3 += vl;
    pA4 += vl;
    pB += vl;
    pB2 += vl;
    pB3 += vl;
    pB4 += vl;

